".navbar {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  z-index: 1000;
  transition: var(--transition);
  padding: 1.5rem 0;
  background: transparent;
}

.navbar--scrolled {
  background: rgba(var(--bg-rgb), 0.8);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  padding: 1rem 0;
  border-bottom: 1px solid rgba(var(--text-rgb), 0.05);
  box-shadow: 0 4px 30px rgba(0, 0, 0, 0.05);
}

.navbar__container {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.navbar__logo {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  text-decoration: none;
}

.navbar__logo-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  background: linear-gradient(135deg, var(--primary), var(--secondary));
  color: white;
  font-weight: 700;
  font-size: 1.2rem;
  border-radius: 12px;
  letter-spacing: -1px;
}

.navbar__logo-text {
  font-weight: 700;
  font-size: 1.25rem;
  color: var(--text);
  letter-spacing: -0.5px;
}

.navbar__menu {
  display: flex;
  align-items: center;
  gap: 2rem;
}

.navbar__list {
  display: flex;
  list-style: none;
  gap: 1.5rem;
  margin: 0;
  padding: 0;
}

.navbar__link {
  color: var(--text-light);
  text-decoration: none;
  font-weight: 500;
  font-size: 0.95rem;
  transition: var(--transition);
  padding: 0.5rem;
}

.navbar__link:hover {
  color: var(--primary);
}

.navbar__actions {
  display: flex;
  align-items: center;
  gap: 1rem;
  padding-inline-start: 1.5rem;
  border-inline-start: 1px solid rgba(var(--text-rgb), 0.1);
}

.navbar__action-btn {
  background: transparent;
  border: none;
  font-size: 1.25rem;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  border-radius: 50%;
  transition: var(--transition);
  color: var(--text);
}

.navbar__action-btn:hover {
  background: rgba(var(--text-rgb), 0.05);
}
